var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"인정할 수 없어...... 인정할 수 없어......","JPN":"認めない……認められないから……","ENG":"No... I can't accept this.","TWN":"我不相信……我不相信……"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"관리국 카운터 아카데미는...... 인류의 영웅을 키워내는 곳이야.","JPN":"管理局カウンターアカデミーは……人類の英雄を育てる場所なの。","ENG":"The Counter Academy... is a place for training humanity's greatest heroes.","TWN":"管理局的制裁者學院……是培養人類英雄的地方。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"훈련도 제대로 안 받고 3류 태스크포스나 전전하다 온 주제에! 체계적인 교육을 받은 나보다 뛰어날 리 없잖아!","JPN":"まともな訓練も受けたこともなくて、三流タスクフォースカンパニーを転々としてきた分際で！　真面目に教育を受けてきた私より優れてるわけがない！","ENG":"She never got any training except from that third-rate TASKFORCE! There's no way she can best me, after all the elite training I've received!","TWN":"沒受過系統訓練，在3流特遣勢力混日子的傢伙！沒道理比我這樣受到系統教育的人強！"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"......그래, 저건 시뮬레이터일 뿐이야. 진짜가 아니야.","JPN":"……そうよ、あれはシミュレーターにすぎない。本物じゃない。","ENG":"Right... That's just a simulator. It's not the real deal.","TWN":"……對，那個只是模擬器而已。不是真實的。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"진짜라면 내가 저 녀석보다 못할 리 없어.","JPN":"本物だったらあいつより私の方が上手くやれる。","ENG":"In real life, there's no way I'd fall behind her.","TWN":"如果是真實情況，我一定比那個傢伙強。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"거기 너! 결투를 신청한다! 시뮬레이터 따위가 아니라 현실에서......!","JPN":"あんたに決闘を挑むわ！　シミュレーターなんかじゃなくて、現実で……！","ENG":"Hey, you! I challenge you to a duel! Not in the simulator, but real life—","TWN":"你！我申請與你決鬥！不是什麼模擬器，而是在現實……！"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"무, 무슨 소리지?","JPN":"な、なんの音？","ENG":"W-what was that?","TWN":"什、什麼聲音？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"침식체? 갑자기 어디서......!","JPN":"侵食体？　いきなりどこから……！","ENG":"A Corrupted Object? Where did it come from?","TWN":"侵蝕體？突然從哪裡冒出來的……!"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"거기서 뭐 하는 거야? 당장 대피하지 않고?!","JPN":"そこで何してるの！　今すぐ逃げて！","ENG":"What are you doing over there? You have to evacuate! Now!","TWN":"你們在幹嘛？快跑啊？！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"대피라니 웃기지 마! 난 네게 결투를 신청했다고!","JPN":"逃げる？　ふざけないで、私はあんたに決闘申請をしたの！","ENG":"Evacuate? Don't make me laugh! I just challenged you to a duel!","TWN":"跑？別搞笑了！我申請與你決鬥！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너야말로 결투 같은 시대착오적인 헛소리 하지 마!","JPN":"あんたこそ状況をみて！　今は決闘どころじゃないよ！","ENG":"A duel? We're not in the 18th century, you moron!","TWN":"決鬥，你在胡說八道什麼！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시뮬레이터가 폭주하고 있어! 어서 사람들을 대피시켜야 돼!","JPN":"シミュレーターが暴走してる！　はやく皆を避難させないと！","ENG":"The simulator is going berserk! We have to evacuate everyone!","TWN":"模擬器正在暴走！要讓其他人趕快撤離！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"시끄러워! 나한테 명령하지 마!","JPN":"うるさい！　私に命令しないで！","ENG":"Shut up! You can't boss me around!","TWN":"吵死了！別命令我！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이 따위 가짜 침식체들은 언제든지 처리할 수 있어!","JPN":"こんな偽物の侵食体なんか、いくらでも相手にできるわ！","ENG":"I can take out these fake C.O.s anytime!","TWN":"這種假的侵蝕體，隨便就能處理掉！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그보다 결투를...... 꺄아악?!","JPN":"だから決闘を……きゃーっ！？","ENG":"But first, the duel... Eeek!","TWN":"決鬥才是……啊啊啊？！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_18"},{"id":"L21_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"자, 잔챙이들 주제에! 당장 떨어지지 못 해?!","JPN":"ざ、雑魚のくせに！　離れろ！","ENG":"Y-you critters don't stand a chance against me! Get off me!","TWN":"你們這些小傢伙們！還不快滾開？！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_HIT_BLADE_BIG_03"},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"소대장이 날 처음 볼 때 어떤 기분이었을지 알 만하네......","JPN":"小隊長が私と会ったばかりの時、こんな気分だったんだろうな……","ENG":"Now I understand how the Commander must have felt when she first met me...","TWN":"我現在能理解小隊長第一次見到我時的心情了……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미, 미나야? 어떡하지?!","JPN":"ミ、ミナちゃん！　どうしよう？","ENG":"M-Mina? What should we do?","TWN":"米、米娜？現在怎麼辦？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......예전에 우리 소대장이 가르쳐준 적이 있어.","JPN":"……以前、うちの小隊長が教えてくれたよ。","ENG":"My Commander once taught me something...","TWN":"……我記得以前小隊長教過我。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐가 뭔지 잘 모를 땐 일단 박살내고 나면 대부분의 문제가 해결된다고.","JPN":"何がどうなっているかわからない時は、とりあえずぶっ潰せばほとんどの問題は解決できるって。","ENG":"When you don't know what to do, smashing your way through solves most problems.","TWN":"不知道該怎麼辦的時候，先把敵人粉碎就能解決大部分問題。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"소, 소대장이라는 분이 꽤 과격하시네.","JPN":"しょ、小隊長という方はかなり過激な性格なんだね。","ENG":"S-sounds like you've got a pretty aggressive commander.","TWN":"那位小隊長，好像有些粗暴。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좀 그런 편이야. 하지만 보통 그 사람 말이 맞긴 하거든.","JPN":"まあね。でもあの人の言うことはよく当たるから。","ENG":"Yeah, I guess. But she's usually right.","TWN":"嗯，確實。不過她說的一般都很正確。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 저 시뮬레이터, 박살내 버려야겠어.","JPN":"だから、あのシミュレーターをぶっ壊すしかない。","ENG":"That's why I'm going to smash that simulator.","TWN":"所以，我得把模擬器毀掉。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 안 돼! 미나야!","JPN":"ダ、ダメだよ！","ENG":"Y-you can't! Mina!","TWN":"啊，不行！米娜！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저게 얼마나 비싼 건데! 학생인 우리가 잘못 건드렸다간 뒷감당 못 해!","JPN":"あれはすごく高いものなの！　生徒の私たちが下手に壊したらとんでもないことになるよ！","ENG":"That thing costs a fortune! Students like us won't be able to handle the consequences!","TWN":"你知道那台機器有多貴嗎！我們這樣的學生弄壞了可賠不起！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장님을 모셔 오자! 아니면 선생님들도 되니까!","JPN":"生徒会長を呼ぼう！　先生でもいいから！","ENG":"Let's go get the Student President instead! Or even the teachers!","TWN":"還是去找學生會長吧！或者去找老師！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"안 돼. 그러면 너무 늦어.","JPN":"いや、もう間に合わない。","ENG":"No. It'll be too late by then.","TWN":"不行。那樣就太晚了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"레이 선배!","JPN":"レイ先輩！","ENG":"Ray!","TWN":"雷伊前輩！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......아, 응!","JPN":"……あ、うん！","ENG":"Oh... Yes?","TWN":"……啊，嗯！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"홀로그램 침식체들이 밖으로 나가면 많은 학생들이 다칠 거야.","JPN":"ホログラムの侵食体たちが外に出てしまったら、多くの生徒たちが怪我をすると思う。","ENG":"If the hologram C.O.s get out, many students will get hurt.","TWN":"全息圖生成的侵蝕體跑到外邊的話，可能會傷到學生。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 내가 시뮬레이터를 부수기 전까지 놈들이 나가지 못하도록 막아 줘.","JPN":"だから私がシミュレーターを壊すまで奴らが出られないように、止めてほしい。","ENG":"So please keep them all in here till I destroy the simulator.","TWN":"所以，在我破壞掉模擬器之前，你幫我擋住敵人。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부탁해. 선배는 공격은 몰라도 방어에는 능숙하니까.","JPN":"お願い。先輩は攻撃は苦手かもしれないけど、防御の才能があるから。","ENG":"I'm counting on you. If there's one thing you're good at, it's defense.","TWN":"拜託你了，我相信前輩的防禦能力。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"......응, 최선을 다해 볼게.","JPN":"……わかった。最善を尽くしてみる。","ENG":"Okay... I'll give it my best.","TWN":"……嗯，我會竭盡全力。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아, 그럼 간다!","JPN":"よし、いくよ！","ENG":"Then here we go!","TWN":"好，那就開始吧！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};